#!/usr/bin/env node
/**
 * code_boss SETUP — production install/release tool. Generated by
 * scripts/build.mjs alongside the app bundle (code-boss.mjs); this is the
 * ONE file an admin copies across the air gap.
 *
 *   node code-boss-setup.mjs [dir] [--no-push]
 *     extract the project source into <dir> (default code_boss-src/), run
 *     scripts/build.mjs --release there, commit, push main + move the
 *     production tag. Repo URL/tag come from ~/.code_boss/build-config.json,
 *     git auth from ~/.code_boss/gitlab-creds.json — prompted on first run
 *     and saved, so re-runs need no typing.
 *
 *   node code-boss-setup.mjs extract [dir] [--force] [--prune]
 *     just recreate the source tree, no build/commit/push.
 *
 * End users never touch this file — they get launch.mjs + the built app.
 */
const BUILD_VERSION = '1408';
import { readFile, writeFile, mkdir, stat, readdir, rename, rm, copyFile } from 'node:fs/promises';
import { existsSync, appendFileSync, mkdirSync } from 'node:fs';
import { spawnSync } from 'node:child_process';
import { createInterface } from 'node:readline';
import { homedir } from 'node:os';
import { fileURLToPath } from 'node:url';
import path from 'node:path';
import zlib from 'node:zlib';


// ====== src/deploy-cmd.mjs ======
/**
 * Deployment subcommands for the single-file bundle (wired in the build footer):
 *
 *   node code-boss.mjs extract [dir] [--force] [--prune]
 *     Reconstructs the project source tree (src/ + scripts/ + docs + deploy/)
 *     from the EMBEDDED_SRC_GZ_B64 blob the build embeds — so ONE copied .mjs
 *     can recreate a buildable repo on the air-gapped production box. Warns
 *     about stale map-owned files the release no longer ships (they would be
 *     re-embedded by the next build); --prune deletes exactly those.
 *
 *   node code-boss.mjs check-update
 *     Compares this bundle's BUILD_VERSION against releases/manifest.json at
 *     the UPDATE_TAG ref of the UPDATE_SOURCE GitLab repo (CONFIG consts in the
 *     bundle header). If newer: downloads the release file, validates it with
 *     `node --check`, swaps it in place (keeping code-boss.prev.mjs for
 *     rollback). Single-flight via code-boss.update.lock — concurrent checkers
 *     skip instead of racing the swap. NEVER blocks a launch: every failure
 *     prints a reason and returns 0 — the launcher runs this best-effort
 *     before starting the app.
 *
 * Auth reuses the app's own stored GitLab credentials
 * (~/.code_boss/gitlab-creds.json, set in the UI) — the launcher never
 * collects or reads secrets itself.
 */

// The build embeds the source map as a module-level const AFTER the bundled
// sources (same pattern as DOCX_HELPER_SOURCES); in the un-bundled dev tree it
// simply doesn't exist. typeof keeps the reference safe in both contexts.
function getEmbeddedSourceMap() {
  /* eslint-disable no-undef */
  if (typeof EMBEDDED_SRC_GZ_B64 === 'undefined' || !EMBEDDED_SRC_GZ_B64) return null;
  const json = zlib.gunzipSync(Buffer.from(EMBEDDED_SRC_GZ_B64, 'base64')).toString('utf8');
  return JSON.parse(json);   // { "src/server.mjs": "<base64 bytes>", ... }
}

// Owned roots = the top-level dirs the embed map ships (src/, scripts/, …).
// Root-level map files are always rewritten by the extract loop, so only
// directories can hide stale files. .git/releases/dist/node_modules are never
// owned and never descended into, even when nested inside an owned root.
async function collectExtractStale(target, map) {
  const ownedRoots = new Set();
  for (const rel of Object.keys(map)) {
    const i = rel.indexOf('/');
    if (i > 0) ownedRoots.add(rel.slice(0, i));
  }
  const never = new Set(['.git', 'releases', 'dist', 'node_modules']);
  // docx-helper/lib holds the POI dependency jars, committed on the prod repo
  // but deliberately NOT embedded (they'd add ~25 MB to the carrier) — they
  // must never be flagged stale or pruned away.
  const neverRel = new Set(['docx-helper/lib', 'docx-helper/target']);
  const stale = [];
  async function walkOwned(relDir) {
    let entries = [];
    try { entries = await readdir(path.join(target, relDir), { withFileTypes: true }); } catch { return; }
    for (const e of entries) {
      const rel = `${relDir}/${e.name}`;
      if (e.isDirectory()) { if (!never.has(e.name) && !neverRel.has(rel)) await walkOwned(rel); }
      else if (!Object.hasOwn(map, rel)) stale.push(rel);
    }
  }
  for (const root of ownedRoots) if (!never.has(root)) await walkOwned(root);
  return stale.sort();
}

async function runExtractCommand({ argv = [] } = {}) {
  const force = argv.includes('--force');
  const prune = argv.includes('--prune');
  const target = path.resolve(argv.find((a) => !a.startsWith('--')) || 'code_boss-src');
  const map = getEmbeddedSourceMap();
  if (!map) {
    console.error('extract: this copy has no embedded source map (running from the dev tree, or built before the embed existed). Build with scripts/build.mjs and use dist/code-boss.mjs.');
    return 1;
  }
  if (existsSync(target)) {
    // A FILE target would slip past the readdir guard (readdir throws →
    // entries stays []) and crash the write loop with a raw ENOTDIR.
    let targetStat = null;
    try { targetStat = await stat(target); } catch {}
    if (targetStat && !targetStat.isDirectory()) {
      console.error(`extract: ${target} exists and is not a directory — choose a directory path.`);
      return 1;
    }
    let entries = [];
    try { entries = await readdir(target); } catch {}
    if (entries.length && !force) {
      console.error(`extract: ${target} is not empty — pass --force to write into it anyway.`);
      return 1;
    }
  }
  const files = Object.keys(map);
  let overwritten = 0;
  for (const rel of files) {
    const abs = path.join(target, rel);
    await mkdir(path.dirname(abs), { recursive: true });
    if (existsSync(abs)) overwritten++;
    await writeFile(abs, Buffer.from(map[rel], 'base64'));
  }
  console.log(`extract: wrote ${files.length} files to ${target} (${overwritten} overwritten, ${files.length - overwritten} new)`);
  // Stale reconcile: a map-owned file this release no longer ships lingers in
  // the production clone forever and gets RE-EMBEDDED by the next release
  // built there. Warn loudly (still exit 0); --prune deletes exactly those.
  const stale = await collectExtractStale(target, map);
  if (stale.length) {
    if (prune) {
      for (const rel of stale) { try { await rm(path.join(target, rel), { force: true }); } catch {} }
      console.log(`extract: pruned ${stale.length} stale file(s): ${stale.join(', ')}`);
    } else {
      console.error(`extract: WARNING — ${stale.length} stale file(s) not part of this release (likely deleted upstream) — remove before building a release (or re-run with --prune):`);
      for (const rel of stale) console.error(`  ${rel}`);
    }
  }
  console.log('next steps there:  npm install (optional, tests only)  →  node scripts/build.mjs --release  →  commit + move the production tag');
  return 0;
}

// ── check-update ────────────────────────────────────────────────────────────

// CB_HOME relocates the user dir for the whole app (see server.mjs) — creds
// must come from the same place the UI writes them.
const cbHomeDir = () => process.env.CB_HOME || homedir();

// ── Release CHANNEL (dev-test vs production) ──────────────────────────────────
// A per-machine pointer the setup run writes (the channel it just deployed) and that the launcher +
// check-update read to pick which moving tag to follow — so the admin can deploy + preview a
// 'devtest' build WITHOUT changing what users get (users never run setup → no channel file →
// 'production', the baked UPDATE_TAG). Lives at <home>/.code_boss/channel (the same path the
// launcher reads as BASE & "\channel").
function channelFilePath() { return path.join(cbHomeDir(), '.code_boss', 'channel'); }
// Which channel/tag a setup invocation targets: --prod → production; bare → devtest (test-first).
function setupChannel(flags = {}) { return flags.prod ? 'production' : 'devtest'; }
// The effective tag to fetch: the local channel pointer if present + non-empty, else the baked default.
async function effectiveChannelTag(fallback = 'production') {
  try { const c = (await readFile(channelFilePath(), 'utf8')).trim(); if (c) return c; } catch {}
  return fallback;
}
async function writeChannelPointer(channel) {
  try { await mkdir(path.dirname(channelFilePath()), { recursive: true }); await writeFile(channelFilePath(), channel + '\n', 'utf8'); return true; } catch (e) { return false; }
}
// Install the just-built app into THIS machine's launcher dir (<home>/.code_boss/app/code-boss.mjs) so the dev
// who ran setup gets the new build on their VERY NEXT launch — without depending on check-update (which on a dev
// box may have no updateSource baked, or can't reach the repo). This automates the manual "copy the file into
// \app" workaround that was the recurring "setup deployed but it still launches the old version" fix. Keeps a
// .prev backup. Returns { ok, build } | { ok:false, reason }.
async function updateLocalApp(target, build) {
  const src = path.join(target, 'dist', 'code-boss.mjs');
  if (!existsSync(src)) return { ok: false, reason: `built app not found at ${src}` };
  const appDir = path.join(cbHomeDir(), '.code_boss', 'app');
  const dest = path.join(appDir, 'code-boss.mjs');
  try {
    await mkdir(appDir, { recursive: true });
    if (existsSync(dest)) { try { await rename(dest, path.join(appDir, 'code-boss.prev.mjs')); } catch {} }   // rollback copy
    await copyFile(src, dest);
    return { ok: true, build, dest };
  } catch (e) { return { ok: false, reason: e?.message || String(e) }; }
}
// Install/refresh THIS machine's desktop shortcuts to point at the just-installed app. The launcher is now the SAME
// file as the app — `node app\code-boss.mjs launch` — so there is no separate launcher file to copy (updateLocalApp
// already put code-boss.mjs in app/). This drops the shortcut icons into app/ and (re)points "Code Boss" +
// "Stop Code Boss" at node.exe running the installed bundle's launch subcommand — because launch's own shortcut
// creation only writes them once and never updates where they point, so an old shortcut would keep running an old
// path. Best-effort: never fails the setup run. (Replaced launch.vbs — security policy blocks .vbs/.hta.)
async function installLocalLauncher(target) {
  const homeCb = path.join(cbHomeDir(), '.code_boss');
  const appDir = path.join(homeCb, 'app');
  const appMjs = path.join(appDir, 'code-boss.mjs');
  try {
    await mkdir(appDir, { recursive: true });
    // Shortcut icons in app/ (from the extracted source tree; the launch subcommand also self-writes them from
    // embedded base64 on first run, so this is just to have them present immediately for the shortcut).
    for (const ico of ['orange-star.ico', 'stop-icon.ico']) {
      const s = path.join(target, 'deploy', ico);
      if (existsSync(s)) { try { await copyFile(s, path.join(appDir, ico)); } catch {} }
    }
    // (Re)point the "Code Boss" + "Stop Code Boss" desktop shortcuts at node.exe running `app\code-boss.mjs launch`,
    // via PowerShell COM (handles a redirected/OneDrive Desktop). q() single-quotes a path AND DOUBLES any embedded
    // single quote (a home path may contain an apostrophe, e.g. C:\Users\O'Brien). WindowStyle=7 opens the brief
    // bootstrap console minimized. A .lnk is not a script, so it runs even where .vbs is blocked.
    let shortcut = false;
    if (process.platform === 'win32') {
      const q = (p) => `'${String(p).replace(/'/g, "''")}'`;
      const ico = path.join(appDir, 'orange-star.ico');
      const stopIco = path.join(appDir, 'stop-icon.ico');
      const node = process.execPath;
      const ps = `$d=[Environment]::GetFolderPath('Desktop'); $ws=New-Object -ComObject WScript.Shell; ` +
        `$s=$ws.CreateShortcut((Join-Path $d 'Code Boss.lnk')); ` +
        `$s.TargetPath=${q(node)}; $s.Arguments=${q('"' + appMjs + '"')}; $s.WorkingDirectory=${q(homeCb)}; $s.WindowStyle=7; ` +
        `if (Test-Path ${q(ico)}) { $s.IconLocation=${q(ico)} }; $s.Save(); ` +
        `$k=$ws.CreateShortcut((Join-Path $d 'Stop Code Boss.lnk')); ` +
        `$k.TargetPath=${q(node)}; $k.Arguments=${q('"' + appMjs + '" --kill')}; $k.WorkingDirectory=${q(homeCb)}; $k.WindowStyle=7; ` +
        `$k.Description='Force-stop all Code Boss processes'; ` +
        `if (Test-Path ${q(stopIco)}) { $k.IconLocation=${q(stopIco)} } elseif (Test-Path ${q(ico)}) { $k.IconLocation=${q(ico)} }; $k.Save()`;
      try { const r = spawnSync('powershell', ['-NoProfile', '-NonInteractive', '-Command', ps], { encoding: 'utf8', timeout: 20000 }); shortcut = r.status === 0; } catch {}
    }
    return { ok: true, appMjs, shortcut };
  } catch (e) { return { ok: false, reason: e?.message || String(e) }; }
}

async function readUpdateCreds() {
  try {
    const raw = await readFile(path.join(cbHomeDir(), '.code_boss', 'gitlab-creds.json'), 'utf8');
    const j = JSON.parse(raw);
    return j && j.token ? j : null;
  } catch { return null; }
}

async function deployApiGet(url, token, { asJson = true, asBuffer = false, timeoutMs = 15000 } = {}) {
  const res = await fetch(url, {
    headers: token ? { 'PRIVATE-TOKEN': token } : {},
    signal: AbortSignal.timeout(timeoutMs),
  });
  if (!res.ok) throw new Error(`HTTP ${res.status} for ${url.replace(/\?.*$/, '')}`);
  if (asBuffer) return Buffer.from(await res.arrayBuffer());   // jars are binary — text() would corrupt them
  if (!asJson) return res.text();
  const text = await res.text();
  // A sign-in/proxy HTML page where JSON belongs is the classic misconfig symptom.
  if (text.trimStart().startsWith('<')) throw new Error('got an HTML page instead of the manifest — check UPDATE_SOURCE and the stored GitLab token');
  return JSON.parse(text);
}

// Single-flight: two launchers checking at once must not both swap (the loser
// would replace the winner's freshly-installed bundle, or worse delete it
// mid-rename). `wx` is atomic; a lock older than ~10 minutes is a crash
// leftover and may be taken over exactly once.
async function acquireUpdateLock(lockPath) {
  for (let attempt = 0; attempt < 2; attempt++) {
    try { await writeFile(lockPath, String(process.pid), { flag: 'wx' }); return true; }
    catch (e) {
      if (e?.code !== 'EEXIST') return false;
      let ageMs = 0;
      try { ageMs = Date.now() - (await stat(lockPath)).mtimeMs; } catch {}
      if (attempt > 0 || ageMs < 10 * 60 * 1000) return false;
      try { await rm(lockPath, { force: true }); } catch {}
    }
  }
  return false;
}

// Pull the prebuilt docx helper + POI dependency jars (manifest.helperJar /
// manifest.jars, staged by `build.mjs --release`) into the same helper home
// the docx plugin already reads (~/.code_boss/docx-helper) — user machines
// then need NO JDK and no manual jar copying. Idempotent via a build marker.
async function syncReleaseJars({ api, manifest: m, creds, updateTag }) {
  if (!m.helperJar || !Array.isArray(m.jars) || !m.jars.length) return;
  const helperHome = path.join(cbHomeDir(), '.code_boss', 'docx-helper');
  const markerPath = path.join(helperHome, 'jars-build.json');
  try {
    const marker = JSON.parse(await readFile(markerPath, 'utf8'));
    if (String(marker.build) === String(m.build)) {
      const all = [path.join(helperHome, 'docx-helper.jar'), ...m.jars.map((j) => path.join(helperHome, 'lib', path.basename(j)))];
      if (all.every((p) => existsSync(p))) return;
    }
  } catch {}
  console.log(`check-update: syncing prebuilt docx helper (build ${m.build}, ${m.jars.length + 1} jars)`);
  await mkdir(path.join(helperHome, 'lib'), { recursive: true });
  const fetchJar = async (repoPath, dest) => {
    const buf = await deployApiGet(`${api}/repository/files/${encodeURIComponent(repoPath)}/raw?ref=${encodeURIComponent(updateTag)}`, creds.token, { asBuffer: true, timeoutMs: 120000 });
    if (!buf || buf.length < 4 || buf.readUInt32BE(0) !== 0x504b0304) throw new Error(`${repoPath} does not look like a jar (zip magic missing)`);
    const tmp = `${dest}.dl.${process.pid}`;
    await writeFile(tmp, buf);
    try { await rename(tmp, dest); }
    catch (e) { try { await rm(tmp, { force: true }); } catch {} throw e; }
  };
  await fetchJar(m.helperJar, path.join(helperHome, 'docx-helper.jar'));
  for (const j of m.jars) await fetchJar(j, path.join(helperHome, 'lib', path.basename(j)));
  await writeFile(markerPath, JSON.stringify({ build: Number(m.build), at: new Date().toISOString() }, null, 2) + '\n', 'utf8');
  console.log('check-update: docx helper jars synced');
}

async function runUpdateCheckCommand({ bundlePath, version, updateSource, updateTag = 'production' } = {}) {
  // PERSIST the update decision: the launcher runs check-update HIDDEN and discards its console, so without
  // this the user can never see WHY a stale build persists. Mirror the key lines to <home>/.code_boss/
  // startup.log (the same file the server writes its listen line to) — so one log answers "did it update,
  // and if not, why?" (BACKLOG #4/#5). Best-effort; never throws.
  const note = (msg) => {
    console.log(msg);
    // Unify into the ONE global diag.log (was a separate startup.log) so check-update decisions interleave with
    // the server's boot/error lines — one file answers "which build, did it update, and if not why?".
    try { mkdirSync(path.join(cbHomeDir(), '.code_boss'), { recursive: true }); appendFileSync(path.join(cbHomeDir(), '.code_boss', 'diag.log'), `${new Date().toISOString()}  INFO  [deploy] | ${msg}\n`, 'utf8'); } catch {}
  };
  const skip = (reason) => { note(`check-update: skipped — ${reason}`); return 0; };
  try {
    if (!updateSource) return skip('UPDATE_SOURCE not configured in this build (set updateSource in ~/.code_boss/build-config.json and rebuild)');
    if (!bundlePath || !existsSync(bundlePath)) return skip(`bundle path not found (${bundlePath})`);
    const creds = await readUpdateCreds();
    if (!creds) return skip('no GitLab credentials yet (~/.code_boss/gitlab-creds.json — set them in the app UI Settings)');
    // Follow this machine's CHANNEL pointer if present (a setup run set it), else the baked default.
    const effTag = await effectiveChannelTag(updateTag);
    if (effTag !== updateTag) note(`check-update: following channel '${effTag}' (local pointer)`);

    // UPDATE_SOURCE is the repo's web URL, e.g. https://gitlab.example.mil/group/code_boss
    const u = new URL(updateSource);
    const projectPath = u.pathname.replace(/^\/+|\/+$/g, '').replace(/\.git$/i, '');   // .git suffix is case-insensitive (matches normalizeRepoUrl)
    const api = `${u.origin}/api/v4/projects/${encodeURIComponent(projectPath)}`;

    const manifest = await deployApiGet(`${api}/repository/files/${encodeURIComponent('releases/manifest.json')}/raw?ref=${encodeURIComponent(effTag)}`, creds.token);
    const m = typeof manifest === 'string' ? JSON.parse(manifest) : manifest;
    if (!m || !m.build || !m.file) return skip('releases/manifest.json at the tag is malformed');
    // The bundle path is always `releases/code-boss-<build>.mjs`; refuse anything
    // outside releases/ or containing a traversal so a tampered manifest can't
    // point check-update at an arbitrary repo file. (Belt-and-suspenders behind
    // the BUILD_VERSION + node --check gates below.)
    if (!/^releases\/[\w.-]+$/.test(String(m.file))) return skip(`manifest file path not under releases/ (${m.file}) — refusing`);

    // Jars sync INDEPENDENTLY of the app version — a user already on the
    // latest app still picks up the prebuilt docx helper the first time a
    // release ships one. Best-effort; never blocks the update or the launch.
    try { await syncReleaseJars({ api, manifest: m, creds, updateTag: effTag }); }
    catch (e) { note(`check-update: jar sync skipped (${e?.message || e})`); }

    if (String(m.build) === String(version)) { note(`check-update: up to date (build ${version})`); return 0; }

    const lockPath = path.join(path.dirname(bundlePath), 'code-boss.update.lock');
    if (!(await acquireUpdateLock(lockPath))) return skip('another check-update is in progress');
    try {
      note(`check-update: build ${m.build} available (running ${version}) — downloading ${m.file}`);
      let body;
      try {
        body = await deployApiGet(`${api}/repository/files/${encodeURIComponent(m.file)}/raw?ref=${encodeURIComponent(effTag)}`, creds.token, { asJson: false, timeoutMs: 120000 });
      } catch (e) {
        return skip(`network error while downloading ${m.file} (${e?.message || e}) — will retry next launch`);
      }
      if (!/BUILD_VERSION/.test(body) || body.length < 200000) return skip('downloaded file does not look like a code_boss bundle');

      // Per-process temp name: a concurrent checker must never clobber (or
      // rm) another's download. Must keep an .mjs extension — `node --check`
      // hard-errors on unknown extensions (ERR_UNKNOWN_FILE_EXTENSION) before
      // even parsing.
      const newPath = path.join(path.dirname(bundlePath), `code-boss.next.${process.pid}.mjs`);
      await writeFile(newPath, body, 'utf8');
      const parse = spawnSync(process.execPath, ['--check', newPath], { encoding: 'utf8' });
      if (parse.status !== 0) {
        try { await rm(newPath, { force: true }); } catch {}
        return skip(`downloaded bundle failed node --check (${(parse.stderr || '').slice(0, 200)})`);
      }

      // Another process may have installed this build while we downloaded —
      // the swap must compare against the file on disk, not our own version.
      let installedBuild = null;
      try { installedBuild = (await readFile(bundlePath, 'utf8')).match(/const BUILD_VERSION = '(\d+)'/)?.[1] ?? null; } catch {}
      if (String(installedBuild) === String(m.build)) {
        try { await rm(newPath, { force: true }); } catch {}
        return skip(`already at build ${m.build} (installed by another process)`);
      }

      const prevPath = path.join(path.dirname(bundlePath), 'code-boss.prev.mjs');
      try { await rm(prevPath, { force: true }); } catch {}
      await rename(bundlePath, prevPath);
      try {
        await rename(newPath, bundlePath);
      } catch (e) {
        // bundlePath must NEVER be left empty: put the previous bundle back.
        try { await rename(prevPath, bundlePath); } catch {}
        try { await rm(newPath, { force: true }); } catch {}
        return skip(`swap failed (${e?.message || e}) — previous bundle restored`);
      }
      note(`check-update: UPDATED build ${version} → ${m.build} (previous kept as code-boss.prev.mjs)`);

      // "What's new": MERGE the user-facing notes into any un-dismissed
      // whats-new.json — never overwrite notes the user has not seen yet. The
      // floor is the build the user last SAW (existing fromBuild), not the
      // build we just replaced. The server serves the file once via
      // /api/whats-new and the UI shows the banner; dismissing deletes it.
      // Best-effort — a notes failure must not un-do a successful update.
      try {
        const wnFile = path.join(path.dirname(bundlePath), 'whats-new.json');
        let existing = null;
        try { existing = JSON.parse(await readFile(wnFile, 'utf8')); } catch {}
        const floorRaw = Number(existing?.fromBuild);
        const floor = Number.isFinite(floorRaw) ? floorRaw : Number(version);
        let entries = [];
        try {
          const hist = JSON.parse(await deployApiGet(`${api}/repository/files/${encodeURIComponent('releases/notes.json')}/raw?ref=${encodeURIComponent(effTag)}`, creds.token, { asJson: false }));
          entries = (Array.isArray(hist) ? hist : [])
            .filter((e) => e && typeof e === 'object')   // one bad element must not nuke the whole history
            .filter((e) => Number(e.build) > floor && Number(e.build) <= Number(m.build));
        } catch {
          // fallback only for genuine upgrades past the user's last-seen build
          if (m.notes && Number(m.build) > floor) entries = [{ build: Number(m.build), title: m.notes.title || '', items: m.notes.items || [] }];
        }
        const carried = Array.isArray(existing?.entries) ? existing.entries.filter((e) => e && typeof e === 'object') : [];
        const seenBuilds = new Set();
        const union = [...entries, ...carried]
          .filter((e) => { const b = Number(e.build); if (seenBuilds.has(b)) return false; seenBuilds.add(b); return true; })
          .sort((x, y) => Number(y.build) - Number(x.build));
        // Write whenever the union is non-empty — even when THIS release added
        // nothing, the rewrite fixes a stale toBuild from a carried-over file.
        if (union.length) {
          await writeFile(wnFile,
            JSON.stringify({ fromBuild: floor, toBuild: Number(m.build), at: new Date().toISOString(), entries: union }, null, 2), 'utf8');
          console.log(`check-update: saved what's-new notes for ${union.length} release(s)`);
        }
      } catch {}
      return 0;
    } finally {
      try { await rm(lockPath, { force: true }); } catch {}
    }
  } catch (e) {
    return skip(e?.message || String(e));
  }
}

// ── setup ───────────────────────────────────────────────────────────────────
// `node code-boss.mjs setup [dir] [--no-push]` — the ONE command an admin runs
// after hand-carrying the bundle to the production box:
//   extract source → release build → git commit → push + move the UPDATE_TAG.
// The copied bundle itself stays OUTSIDE the repo (extraction goes into a
// subdirectory), so it is never committed. Config (repo URL/tag) lives in
// ~/.code_boss/build-config.json and creds in ~/.code_boss/gitlab-creds.json —
// setup prompts for whichever is missing (TTY only) and saves them, so the
// command line never carries secrets and re-runs need no typing at all.

async function setupPromptLine(question) {
  if (!process.stdin.isTTY) return '';
  const rl = createInterface({ input: process.stdin, output: process.stdout });
  const answer = await new Promise((resolve) => rl.question(question, resolve));
  rl.close();
  return String(answer || '').trim();
}

// Accept a GitLab repo URL in whatever shape a user pastes and return the clean
// web URL: no embedded auth, no trailing slash, no pasted browser tail
// (…/-/tree/main), and WITH-OR-WITHOUT a trailing .git both fine (downstream the
// push remote re-adds .git and the API path strips it — so the stored form just
// needs to be the canonical web URL). scp-style (git@host:group/repo) is
// converted to https. Non-http sources (a local bare repo in tests) pass through
// untouched. Returns '' for empty input.
function normalizeRepoUrl(raw) {
  let s = String(raw == null ? '' : raw).trim().replace(/^['"]+|['"]+$/g, '').trim();
  if (!s) return '';
  const scp = /^[\w.+-]+@([\w.-]+):(.+)$/.exec(s);          // git@host:group/repo[.git]
  if (scp && !/^[a-z][\w+.-]*:\/\//i.test(s)) s = 'https://' + scp[1] + '/' + scp[2];
  if (/^https?:\/\//i.test(s)) {
    try {
      const u = new URL(s);
      u.username = ''; u.password = ''; u.hash = ''; u.search = '';
      u.pathname = u.pathname.replace(/\/-\/.*$/, '').replace(/\/+$/, '').replace(/\.git$/i, '').replace(/\/+$/, '');
      s = u.origin + u.pathname;
    } catch { /* unparseable — return the trimmed input so the caller errors clearly */ }
  }
  return s;
}

// Minimal flag parser for the setup CLI: supports `--flag value`, `--flag=value`,
// boolean `--no-push`, and bare positionals (the target dir). Returns { flags,
// positionals } so a flag VALUE is never mistaken for the positional target dir.
function parseSetupArgs(argv) {
  const flags = {}, positionals = [];
  const BOOL = new Set(['no-push', 'prod']);
  for (let i = 0; i < argv.length; i++) {
    const m = /^--([\w-]+)(?:=([\s\S]*))?$/.exec(argv[i]);
    if (!m) { positionals.push(argv[i]); continue; }
    const key = m[1];
    if (m[2] !== undefined) flags[key] = m[2];
    else if (BOOL.has(key)) flags[key] = true;
    else if (i + 1 < argv.length && !/^--/.test(argv[i + 1])) flags[key] = argv[++i];
    else flags[key] = true;
  }
  return { flags, positionals };
}

async function ensureSetupConfig({ sourceArg, tagArg } = {}) {
  const dir = path.join(cbHomeDir(), '.code_boss');
  await mkdir(dir, { recursive: true });
  const cfgPath = path.join(dir, 'build-config.json');
  let cfg = {};
  try { const j = JSON.parse(await readFile(cfgPath, 'utf8')); if (j && typeof j === 'object') cfg = j; } catch {}
  // updateSource precedence: explicit --source flag > env > value already on disk
  // > interactive prompt. The flag/env paths exist because the interactive
  // readline is unreliable in some Windows terminals (the prompt can return
  // empty without waiting), which silently produced "updateSource is not set".
  let src = String(sourceArg || '').trim()
    || String(process.env.CB_UPDATE_SOURCE || process.env.UPDATE_SOURCE || '').trim()
    || String(cfg.updateSource || '').trim();
  if (!src) src = await setupPromptLine('GitLab repo web URL that will host this app (e.g. https://gitlab.example.mil/group/code_boss): ');
  src = normalizeRepoUrl(src);
  if (!src) {
    console.error(`setup: updateSource is not set. Provide the GitLab repo web URL one of these ways and re-run:
  flag:  node code-boss-setup.mjs --source https://gitlab.example.mil/group/code_boss
  env:   CB_UPDATE_SOURCE   (PowerShell:  $env:CB_UPDATE_SOURCE = 'https://gitlab.example.mil/group/code_boss')
  file:  add "updateSource" to ${cfgPath}
(The URL is accepted with or without a trailing .git.)`);
    return null;
  }
  cfg.updateSource = src;
  cfg.updateTag = String(tagArg || '').trim() || String(cfg.updateTag || '').trim() || String(process.env.CB_UPDATE_TAG || '').trim() || 'production';
  await writeFile(cfgPath, JSON.stringify(cfg, null, 2) + '\n', 'utf8');
  return cfg;
}

async function ensureSetupCreds({ userArg, tokenArg } = {}) {
  const credsPath = path.join(cbHomeDir(), '.code_boss', 'gitlab-creds.json');
  let creds = {};
  try { const j = JSON.parse(await readFile(credsPath, 'utf8')); if (j && typeof j === 'object') creds = j; } catch {}
  // Same precedence as the repo URL: flag > env > on disk > prompt. (Creds went
  // through the same unreliable readline, so they get the same non-interactive
  // escape hatches.)
  let user = String(userArg || '').trim() || String(process.env.CB_GITLAB_USER || '').trim() || String(creds.user || '').trim();
  let token = String(tokenArg || '').trim() || String(process.env.CB_GITLAB_TOKEN || '').trim() || String(creds.token || '').trim();
  if (!user) user = await setupPromptLine('GitLab username: ');
  if (!token) token = await setupPromptLine('GitLab access token (needs api + write_repository): ');
  if (!user || !token) {
    console.error(`setup: GitLab credentials missing — pass --gl-user/--gl-token, set CB_GITLAB_USER/CB_GITLAB_TOKEN, or write {"user":"…","token":"…"} to ${credsPath}, then re-run.`);
    return null;
  }
  creds = { ...creds, user, token };
  await mkdir(path.dirname(credsPath), { recursive: true });
  await writeFile(credsPath, JSON.stringify(creds, null, 2) + '\n', 'utf8');
  return creds;
}

// Push auth rides the URL for the one push call only — the stored remote (and
// therefore .git/config) never contains the token. Non-http sources (a local
// bare repo in tests, ssh) pass through untouched.
function setupAuthedRemote(updateSource, creds) {
  if (!/^https?:/i.test(updateSource)) return updateSource;
  const u = new URL(updateSource);
  u.username = creds.user;
  u.password = creds.token;
  if (!u.pathname.endsWith('.git')) u.pathname = u.pathname.replace(/\/+$/, '') + '.git';
  return u.href;
}

function setupGitRun(target, args, { allowFail = false } = {}) {
  const r = spawnSync('git', args, { cwd: target, encoding: 'utf8' });
  if (r.status !== 0 && !allowFail) {
    // Never echo an authed URL in errors.
    const shown = args.map((a) => a.replace(/\/\/[^@/]+@/, '//***@'));
    throw new Error(`git ${shown.join(' ')} failed: ${(r.stderr || r.stdout || '').replace(/\/\/[^@/]+@/g, '//***@').trim().slice(0, 400)}`);
  }
  return r;
}

async function runSetupCommand({ argv = [], bundlePath } = {}) {
  try {
    const { flags, positionals } = parseSetupArgs(argv);
    const target = path.resolve(positionals[0] || 'code_boss-src');
    const noPush = !!flags['no-push'];
    // CHANNEL: a bare run deploys to 'devtest' (test it yourself first); --prod blesses 'production'
    // (what users get). The moving tag pushed below is this channel — NOT cfg.updateTag (which stays
    // the BAKED user default 'production'). The channel is also written locally so THIS machine's
    // launcher opens the channel we just deployed.
    const channel = setupChannel(flags);
    console.log(`setup: channel = ${channel.toUpperCase()}${channel === 'devtest' ? '  (run with --prod to release to users)' : '  (this is what users get)'}`);
    if (bundlePath) {
      const bp = path.resolve(bundlePath);
      const inTarget = process.platform === 'win32'
        ? bp.toLowerCase().startsWith(target.toLowerCase() + path.sep)
        : bp.startsWith(target + path.sep);
      if (inTarget) {
        console.error('setup: this bundle file sits INSIDE the target directory — it would be committed with the source. Move it out (or pass a different target dir) and re-run.');
        return 1;
      }
    }
    const haveGit = spawnSync('git', ['--version'], { encoding: 'utf8' });
    if (haveGit.status !== 0) { console.error('setup: git not found on PATH — install git and re-run.'); return 1; }

    const cfg = await ensureSetupConfig({ sourceArg: flags.source || flags.url, tagArg: flags.tag });
    if (!cfg) return 1;
    const creds = noPush ? null : await ensureSetupCreds({ userArg: flags['gl-user'], tokenArg: flags['gl-token'] });
    if (!noPush && !creds) return 1;

    // [1/4] extract — anything already there (a prior clone) reconciles fully.
    const reSetup = existsSync(path.join(target, '.git'));
    const exArgs = [target];
    if (existsSync(target)) exArgs.push('--force', '--prune');
    console.log(`setup: [1/4] extracting source into ${target}${reSetup ? ' (existing repo — force + prune)' : ''}`);
    const ex = await runExtractCommand({ argv: exArgs });
    if (ex !== 0) return ex;

    // [2/4] release build — reads ~/.code_boss/build-config.json for UPDATE_SOURCE.
    console.log('setup: [2/4] building a release (node scripts/build.mjs --release)');
    const b = spawnSync(process.execPath, ['scripts/build.mjs', '--release'], { cwd: target, stdio: 'inherit' });
    if (b.status !== 0) { console.error('setup: build failed — fix the error above and re-run.'); return 1; }

    // [3/4] commit + tag.
    console.log('setup: [3/4] committing');
    if (!reSetup) setupGitRun(target, ['init']);
    const email = setupGitRun(target, ['config', 'user.email'], { allowFail: true });
    if (!(email.stdout || '').trim()) {
      const who = creds?.user || 'code-boss';
      setupGitRun(target, ['config', 'user.name', who]);
      setupGitRun(target, ['config', 'user.email', `${who}@code-boss.local`]);
    }
    setupGitRun(target, ['add', '-A']);
    let build = '?';
    try { build = (await readFile(path.join(target, 'scripts', 'build-number.txt'), 'utf8')).trim(); } catch {}
    const c = setupGitRun(target, ['commit', '-m', `Release build ${build}`], { allowFail: true });
    if (c.status !== 0 && !/nothing to commit|nothing added/i.test((c.stdout || '') + (c.stderr || ''))) {
      throw new Error(`git commit failed: ${(c.stderr || c.stdout || '').trim().slice(0, 400)}`);
    }
    setupGitRun(target, ['branch', '-M', 'main']);
    setupGitRun(target, ['tag', '-f', channel]);

    // [4/4] push main + the moving CHANNEL tag (devtest by default; production with --prod).
    if (noPush) {
      console.log(`setup: [4/4] push SKIPPED (--no-push) — when ready: git push <remote> main && git push -f <remote> ${channel}`);
    } else {
      console.log(`setup: [4/4] pushing main + tag '${channel}' to ${cfg.updateSource}`);
      const remote = setupAuthedRemote(cfg.updateSource, creds);
      // ATOMIC: main + the moving channel tag land together or not at all. A
      // non-atomic two-push could advance main but leave the tag (clients stay
      // pinned to the OLD release). --atomic + --force-with-lease for the tag.
      const atomic = setupGitRun(target, ['push', '--atomic', '--force', remote, 'main', `refs/tags/${channel}`], { allowFail: true });
      if (atomic && atomic.status !== 0) {
        // Old git / server without atomic support → fall back, tag LAST, and warn loudly on a half-apply.
        console.log('setup: --atomic push unsupported here — falling back to sequential (tag last)');
        setupGitRun(target, ['push', remote, 'main']);
        const tagPush = setupGitRun(target, ['push', '-f', remote, `refs/tags/${channel}`], { allowFail: true });
        if (tagPush && tagPush.status !== 0) {
          console.log(`setup: ⚠ RELEASE HALF-APPLIED — main advanced but tag '${channel}' did NOT update; clients keep the OLD build. Re-run: git push -f ${cfg.updateSource} refs/tags/${channel}`);
        }
      }
    }
    // Point THIS machine's launcher at the channel we just deployed (users have no such file →
    // they stay on the baked 'production' tag). This is the "shortcut opens the last-deployed channel".
    if (await writeChannelPointer(channel)) console.log(`setup: this machine's launcher will now open the '${channel}' channel (delete ${channelFilePath()} to revert to the default).`);
    else console.log(`setup: ⚠ could not write the channel pointer (${channelFilePath()}); the launcher will use the baked default tag.`);

    // Install the new build into THIS machine's app dir so the dev's NEXT launch runs it immediately — without
    // relying on check-update (the recurring "setup deployed but it still launches the old version" cause: a dev
    // box whose local app has no updateSource baked / can't reach the repo never self-updates). End users are
    // unaffected — they have no local build and still update via check-update.
    const localApp = await updateLocalApp(target, build);
    if (localApp.ok) console.log(`setup: installed build ${build} into this machine's app (${localApp.dest}) — your next launch runs it now, no update check needed.`);
    else console.log(`setup: ⚠ could not install the build into this machine's app (${localApp.reason}); a launch will fall back to check-update.`);

    // Also refresh THIS machine's launcher + desktop shortcut from the same carrier, so the whole install comes
    // from the one file. (Not needed just to update the app — the existing launcher already runs the new \app —
    // but it keeps the launcher itself current and the shortcut pointing at it.)
    const localLauncher = await installLocalLauncher(target);
    if (localLauncher.ok) console.log(`setup: refreshed this machine's desktop shortcuts${localLauncher.shortcut ? ' → they now run `node "' + localLauncher.appMjs + '"`' : ' (not updated — run `node app\\code-boss.mjs`)'}.`);
    else console.log(`setup: ⚠ could not refresh the local shortcuts (${localLauncher.reason}); your existing app still runs the new build.`);

    console.log(`\nsetup: DONE (build ${build}) on the '${channel}' channel. Hand users ONE file: ${path.join(target, 'releases', `code-boss-${build}.mjs`)} (rename to code-boss.mjs). They run: node code-boss.mjs`);
    console.log(`(offline handout — no repo pull at launch; the app updates itself via check-update against the '${channel}' tag)`);
    console.log(`\`launch\` self-installs the bundle into ~/.code_boss/app, starts the server, opens Chrome, and drops desktop shortcuts (best-effort) so later launches are one click.`);
    console.log(`This machine's launcher now follows '${channel}' → it check-updates against the '${channel}' tag (app + docx jars).`);
    if (channel !== 'production') {
      console.log(`NOTE: '${channel}' is a TEST channel — production users do NOT get this build, and an EXISTING install older than the channel feature (it checks 'production') will NOT auto-pull it. To bump such an install on THIS box right now:`);
      console.log(`        copy /Y "${path.join(target, 'releases', `code-boss-${build}.mjs`)}" "%USERPROFILE%\\.code_boss\\app\\code-boss.mjs"`);
      console.log(`      When ready for everyone, re-run with --prod (moves the 'production' tag; all installs then update normally).`);
    }
    return 0;
  } catch (e) {
    console.error('setup: FAILED —', e?.message || e);
    return 1;
  }
}

// ====== embedded project source map ======
const EMBEDDED_SRC_GZ_B64 = '';


(async () => {
  if (process.argv[2] === 'extract') {
    try { process.exit(await runExtractCommand({ argv: process.argv.slice(3) })); }
    catch (e) { console.error('[code_boss-setup] extract failed:', e?.stack || e?.message || e); process.exit(1); }
    return;
  }
  console.log('[code_boss-setup] build ' + BUILD_VERSION + ' — production install/release (extract + build + commit + push + tag)');
  try { process.exit(await runSetupCommand({ argv: process.argv.slice(2), bundlePath: fileURLToPath(import.meta.url) })); }
  catch (e) { console.error('[code_boss-setup] setup failed:', e?.stack || e?.message || e); process.exit(1); }
})();
